sys_script_client.script:
function onLoad() {

    var plugDetails = new GlideRecord('u_ev_plugs');
	plugDetails.addQuery('name', g_form.getValue(u_plug_type));
	plugDetails.query();

	g_form.setValue('u_cm_box', plugDetails.u_charging_method);
	g_form.setValue('u_si_box', plugDetails.u_supply_input);
	g_form.setValue('u_cm_box', plugDetails.u_max_op);
	g_form.setValue('u_ox_box', plugDetails.u_max_oc);
	g_form.setValue('u_md_box', plugDetails.u_market_designation);
	g_form.setValue('u_manu_box', plugDetails.manufacturer);
	g_form.setValue('u_cost_box', plugDetails.cost);

}
